package com.david.tiendavirtual.ui.home

import android.view.LayoutInflater
import android.view.ViewGroup
import androidx.recyclerview.widget.RecyclerView
import com.david.tiendavirtual.R
import com.david.tiendavirtual.data.model.Categoria
import com.david.tiendavirtual.databinding.ItemCategoriaHomeBinding

class CategoriaHomeAdapter(
    private var categorias: List<Categoria>,
    private val onCategoria: (Categoria?) -> Unit
) : RecyclerView.Adapter<CategoriaHomeAdapter.VH>() {

    private var seleccionado: Int = -1  // -1 = "Todas"

    inner class VH(val b: ItemCategoriaHomeBinding) : RecyclerView.ViewHolder(b.root)

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int) =
        VH(ItemCategoriaHomeBinding.inflate(LayoutInflater.from(parent.context), parent, false))

    override fun getItemCount() = categorias.size + 1

    override fun onBindViewHolder(holder: VH, position: Int) {
        val ctx = holder.b.root.context

        if (position == 0) {
            holder.b.tvCategoriaNombre.text = "Todas"
            holder.b.ivCategoriaIcon.setImageResource(R.drawable.ic_home)
            aplicarEstilo(holder, seleccionado == -1, ctx)
            holder.b.root.setOnClickListener {
                val prev = seleccionado; seleccionado = -1
                notifyItemChanged(0)
                if (prev >= 0) notifyItemChanged(prev + 1)
                onCategoria(null)
            }
        } else {
            val cat = categorias[position - 1]
            holder.b.tvCategoriaNombre.text = cat.nombre
            holder.b.ivCategoriaIcon.setImageResource(iconoPorNombre(cat.nombre))
            aplicarEstilo(holder, seleccionado == position - 1, ctx)
            holder.b.root.setOnClickListener {
                val prev = seleccionado; seleccionado = position - 1
                notifyItemChanged(0)
                if (prev >= 0) notifyItemChanged(prev + 1)
                notifyItemChanged(position)
                onCategoria(cat)
            }
        }
    }

    private fun aplicarEstilo(holder: VH, selected: Boolean, ctx: android.content.Context) {
        if (selected) {
            holder.b.root.strokeColor = ctx.getColor(R.color.green_primary)
            holder.b.root.strokeWidth = 2
            holder.b.tvCategoriaNombre.setTextColor(ctx.getColor(R.color.green_primary))
        } else {
            holder.b.root.strokeColor = ctx.getColor(R.color.card_stroke)
            holder.b.root.strokeWidth = 1
            holder.b.tvCategoriaNombre.setTextColor(ctx.getColor(R.color.text_primary))
        }
        holder.b.ivCategoriaIcon.setColorFilter(ctx.getColor(R.color.green_primary))
    }

    private fun iconoPorNombre(nombre: String): Int {
        val n = nombre.lowercase()
        return when {
            n.contains("disco") || n.contains("ssd") || n.contains("hdd") -> R.drawable.ic_inventory_box
            n.contains("fuente") || n.contains("poder") || n.contains("psu") -> R.drawable.ic_inventory_box
            n.contains("memoria") || n.contains("ram") -> R.drawable.ic_inventory_box
            n.contains("madre") || n.contains("tarjeta") || n.contains("mainboard") -> R.drawable.ic_inventory_box
            n.contains("procesador") || n.contains("cpu") -> R.drawable.ic_inventory_box
            else -> R.drawable.ic_inventory_box
        }
    }

    fun actualizar(nuevas: List<Categoria>) {
        categorias = nuevas
        seleccionado = -1
        notifyDataSetChanged()
    }
}

package com.david.tiendavirtual.ui.home

import android.view.LayoutInflater
import android.view.ViewGroup
import androidx.recyclerview.widget.RecyclerView
import com.david.tiendavirtual.R
import com.david.tiendavirtual.data.model.Categoria
import com.david.tiendavirtual.databinding.ItemCategoriaHomeBinding

class CategoriaHomeAdapter(
    private var categorias: List<Categoria>,
    private val onCategoria: (Categoria?) -> Unit
) : RecyclerView.Adapter<CategoriaHomeAdapter.VH>() {

    private var seleccionado: Int = -1  // -1 = "Todas"

    inner class VH(val b: ItemCategoriaHomeBinding) : RecyclerView.ViewHolder(b.root)

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int) =
        VH(ItemCategoriaHomeBinding.inflate(LayoutInflater.from(parent.context), parent, false))

    override fun getItemCount() = categorias.size + 1

    override fun onBindViewHolder(holder: VH, position: Int) {
        val ctx = holder.b.root.context

        if (position == 0) {
            holder.b.tvCategoriaNombre.text = "Todas"
            holder.b.ivCategoriaIcon.setImageResource(R.drawable.ic_home)
            aplicarEstilo(holder, seleccionado == -1, ctx)
            holder.b.root.setOnClickListener {
                val prev = seleccionado; seleccionado = -1
                notifyItemChanged(0)
                if (prev >= 0) notifyItemChanged(prev + 1)
                onCategoria(null)
            }
        } else {
            val cat = categorias[position - 1]
            holder.b.tvCategoriaNombre.text = cat.nombre
            holder.b.ivCategoriaIcon.setImageResource(iconoPorNombre(cat.nombre))
            aplicarEstilo(holder, seleccionado == position - 1, ctx)
            holder.b.root.setOnClickListener {
                val prev = seleccionado; seleccionado = position - 1
                notifyItemChanged(0)
                if (prev >= 0) notifyItemChanged(prev + 1)
                notifyItemChanged(position)
                onCategoria(cat)
            }
        }
    }

    private fun aplicarEstilo(holder: VH, selected: Boolean, ctx: android.content.Context) {
        if (selected) {
            holder.b.root.strokeColor = ctx.getColor(R.color.green_primary)
            holder.b.root.strokeWidth = 2
            holder.b.tvCategoriaNombre.setTextColor(ctx.getColor(R.color.green_primary))
        } else {
            holder.b.root.strokeColor = ctx.getColor(R.color.card_stroke)
            holder.b.root.strokeWidth = 1
            holder.b.tvCategoriaNombre.setTextColor(ctx.getColor(R.color.text_primary))
        }
        // Solo aplicar tinte verde a íconos genéricos, no a fotos reales
        if (esIconoGenerico(holder.b.ivCategoriaIcon.drawable)) {
            holder.b.ivCategoriaIcon.setColorFilter(ctx.getColor(R.color.green_primary))
        } else {
            holder.b.ivCategoriaIcon.clearColorFilter()
        }
    }

    private fun esIconoGenerico(drawable: android.graphics.drawable.Drawable?): Boolean {
        // Las fotos (BitmapDrawable) no llevan tinte; los vectores sí
        return drawable !is android.graphics.drawable.BitmapDrawable
    }

    private fun iconoPorNombre(nombre: String): Int {
        val n = nombre.lowercase()
        return when {
            n.contains("procesador") || n.contains("cpu") -> R.drawable.procesadores
            n.contains("memoria") || n.contains("ram") -> R.drawable.ram
            n.contains("madre") || n.contains("tarjeta madre") || n.contains("mainboard") -> R.drawable.tarjetasmadre
            n.contains("disco") || n.contains("ssd") || n.contains("hdd") -> R.drawable.ic_inventory_box
            n.contains("fuente") || n.contains("poder") || n.contains("psu") -> R.drawable.ic_inventory_box
            else -> R.drawable.ic_inventory_box
        }
    }

    fun actualizar(nuevas: List<Categoria>) {
        categorias = nuevas
        seleccionado = -1
        notifyDataSetChanged()
    }
}

package com.david.tiendavirtual.ui.login

import android.content.Intent
import android.os.Bundle
import android.view.View
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.core.view.WindowCompat
import com.android.volley.Request.Method
import com.android.volley.toolbox.StringRequest
import com.android.volley.toolbox.Volley
import com.david.tiendavirtual.R
import com.david.tiendavirtual.data.model.UserSession
import com.david.tiendavirtual.data.network.ApiConfig
import com.david.tiendavirtual.databinding.ActivityLoginBinding
import com.david.tiendavirtual.ui.admin.AdminMainActivity
import com.david.tiendavirtual.ui.empleado.EmpleadoMainActivity
import com.david.tiendavirtual.ui.home.MainActivity
import org.json.JSONObject

class LoginActivity : AppCompatActivity() {

    private lateinit var binding: ActivityLoginBinding

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        binding = ActivityLoginBinding.inflate(layoutInflater)
        setContentView(binding.root)

        window.statusBarColor = getColor(R.color.green_primary)
        WindowCompat.getInsetsController(window, binding.root).isAppearanceLightStatusBars = false

        // ── Tabs ──────────────────────────────────────────────────────────
        binding.tabLogin.setOnClickListener    { mostrarLogin() }
        binding.tabRegistro.setOnClickListener { mostrarRegistro() }
        binding.tvIrARegistro.setOnClickListener { mostrarRegistro() }
        binding.tvIrALogin.setOnClickListener    { mostrarLogin() }

        // ── Login ─────────────────────────────────────────────────────────
        binding.btnLogin.setOnClickListener {
            val usuario    = binding.etUsuario.text.toString().trim()
            val contrasena = binding.etContrasena.text.toString().trim()
            if (usuario.isEmpty() || contrasena.isEmpty()) {
                Toast.makeText(this, "Completa usuario y contraseña", Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }
            iniciarSesion(usuario, contrasena)
        }

        // ── Continuar sin login (modo cliente) ───────────────────────────
        binding.btnContinuarSinLogin.setOnClickListener {
            UserSession.limpiar()
            startActivity(Intent(this, MainActivity::class.java))
            finish()
        }

        // ── Registro ──────────────────────────────────────────────────────
        binding.btnRegistrar.setOnClickListener {
            val nombre    = binding.etNombreReg.text.toString().trim()
            val apellido  = binding.etApellidoReg.text.toString().trim()
            val usuario   = binding.etUsuarioReg.text.toString().trim()
            val correo    = binding.etCorreoReg.text.toString().trim()
            val password  = binding.etPasswordReg.text.toString().trim()
            val confirmar = binding.etConfirmReg.text.toString().trim()

            if (nombre.isEmpty() || apellido.isEmpty() || usuario.isEmpty() ||
                correo.isEmpty() || password.isEmpty() || confirmar.isEmpty()) {
                Toast.makeText(this, "Completa todos los campos", Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }
            if (password != confirmar) {
                Toast.makeText(this, "Las contraseñas no coinciden", Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }
            registrar(nombre, apellido, usuario, correo, password)
        }
    }

    // ── Helpers de tab ───────────────────────────────────────────────────
    private fun mostrarLogin() {
        binding.layoutLogin.visibility    = View.VISIBLE
        binding.layoutRegistro.visibility = View.GONE
        binding.tvTabLogin.setTextColor(getColor(R.color.green_primary))
        binding.tvTabLogin.setTypeface(null, android.graphics.Typeface.BOLD)
        binding.viewLineaLogin.visibility = View.VISIBLE
        binding.tvTabRegistro.setTextColor(getColor(R.color.text_secondary))
        binding.tvTabRegistro.setTypeface(null, android.graphics.Typeface.NORMAL)
        binding.viewLineaRegistro.visibility = View.INVISIBLE
    }

    private fun mostrarRegistro() {
        binding.layoutLogin.visibility    = View.GONE
        binding.layoutRegistro.visibility = View.VISIBLE
        binding.tvTabRegistro.setTextColor(getColor(R.color.green_primary))
        binding.tvTabRegistro.setTypeface(null, android.graphics.Typeface.BOLD)
        binding.viewLineaRegistro.visibility = View.VISIBLE
        binding.tvTabLogin.setTextColor(getColor(R.color.text_secondary))
        binding.tvTabLogin.setTypeface(null, android.graphics.Typeface.NORMAL)
        binding.viewLineaLogin.visibility = View.INVISIBLE
    }

    // ── Login: validar y redirigir según rol ─────────────────────────────
    private fun iniciarSesion(usuario: String, contrasena: String) {
        val queue = Volley.newRequestQueue(this)
        val request = object : StringRequest(
            Method.POST, ApiConfig.LOGIN,
            { response ->
                try {
                    val json = JSONObject(response)
                    if (json.getBoolean("ok")) {
                        val u = json.getJSONObject("usuario")
                        UserSession.usuario  = u.optString("usuario",  "")
                        UserSession.nombre   = u.optString("nombre",   "")
                        UserSession.apellido = u.optString("apellido", "")
                        UserSession.rol      = u.optString("rol",      "2")

                        // ── Redirigir según rol ──────────────────────────
                        val destino: Class<*> = when {
                            UserSession.isAdmin    -> AdminMainActivity::class.java
                            UserSession.isEmpleado -> EmpleadoMainActivity::class.java
                            else                   -> MainActivity::class.java
                        }
                        startActivity(Intent(this, destino))
                        finish()
                    } else {
                        Toast.makeText(this, json.getString("mensaje"), Toast.LENGTH_SHORT).show()
                    }
                } catch (_: Exception) {
                    Toast.makeText(this, "Error procesando respuesta", Toast.LENGTH_SHORT).show()
                }
            },
            { error -> Toast.makeText(this, error.message ?: "Error de red", Toast.LENGTH_SHORT).show() }
        ) {
            override fun getParams() = mapOf("usuario" to usuario, "contrasena" to contrasena)
        }
        queue.add(request)
    }

    // ── Registro: enviar correo para que el servidor asigne el rol ───────
    private fun registrar(nombre: String, apellido: String, usuario: String,
                          correo: String, contrasena: String) {
        val queue = Volley.newRequestQueue(this)
        val request = object : StringRequest(
            Method.POST, ApiConfig.REGISTER,
            { response ->
                try {
                    val json = JSONObject(response)
                    if (json.getBoolean("ok")) {
                        Toast.makeText(this, json.optString("mensaje",
                            "¡Cuenta creada! Ahora inicia sesión"), Toast.LENGTH_LONG).show()
                        binding.etNombreReg.text?.clear()
                        binding.etApellidoReg.text?.clear()
                        binding.etUsuarioReg.text?.clear()
                        binding.etCorreoReg.text?.clear()
                        binding.etPasswordReg.text?.clear()
                        binding.etConfirmReg.text?.clear()
                        mostrarLogin()
                    } else {
                        Toast.makeText(this, json.getString("mensaje"), Toast.LENGTH_SHORT).show()
                    }
                } catch (_: Exception) {
                    Toast.makeText(this, "Error procesando respuesta", Toast.LENGTH_SHORT).show()
                }
            },
            { error -> Toast.makeText(this, error.message ?: "Error de red", Toast.LENGTH_SHORT).show() }
        ) {
            override fun getParams() = mapOf(
                "nombre"     to nombre,
                "apellido"   to apellido,
                "usuario"    to usuario,
                "correo"     to correo,
                "contrasena" to contrasena
            )
        }
        queue.add(request)
    }
}

package com.david.tiendavirtual.ui.login

import android.content.Intent
import android.os.Bundle
import android.view.View
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.core.view.WindowCompat
import com.android.volley.Request.Method
import com.android.volley.toolbox.StringRequest
import com.android.volley.toolbox.Volley
import com.david.tiendavirtual.R
import com.david.tiendavirtual.data.model.UserSession
import com.david.tiendavirtual.data.network.ApiConfig
import com.david.tiendavirtual.databinding.ActivityLoginBinding
import com.david.tiendavirtual.ui.admin.AdminMainActivity
import com.david.tiendavirtual.ui.empleado.EmpleadoMainActivity
import com.david.tiendavirtual.ui.home.MainActivity
import org.json.JSONObject

class LoginActivity : AppCompatActivity() {

    private lateinit var binding: ActivityLoginBinding

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        binding = ActivityLoginBinding.inflate(layoutInflater)
        setContentView(binding.root)

        window.statusBarColor = getColor(R.color.green_primary)
        WindowCompat.getInsetsController(window, binding.root).isAppearanceLightStatusBars = false

        // ── Tabs ──────────────────────────────────────────────────────────
        binding.tabLogin.setOnClickListener    { mostrarLogin() }
        binding.tabRegistro.setOnClickListener { mostrarRegistro() }
        binding.tvIrARegistro.setOnClickListener { mostrarRegistro() }
        binding.tvIrALogin.setOnClickListener    { mostrarLogin() }

        // ── Login ─────────────────────────────────────────────────────────
        binding.btnLogin.setOnClickListener {
            if (validarLogin()) {
                val usuario    = binding.etUsuario.text.toString().trim()
                val contrasena = binding.etContrasena.text.toString().trim()
                iniciarSesion(usuario, contrasena)
            }
        }

        // Limpiar error al escribir
        binding.etUsuario.addTextChangedListener(android.text.TextWatcher() {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) {}
            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                binding.tilUsuario.error = null
            }
            override fun afterTextChanged(s: android.text.Editable?) {}
        })
        binding.etContrasena.addTextChangedListener(android.text.TextWatcher() {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) {}
            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                binding.tilContrasena.error = null
            }
            override fun afterTextChanged(s: android.text.Editable?) {}
        })

        // ── Continuar sin login (modo cliente) ───────────────────────────
        binding.btnContinuarSinLogin.setOnClickListener {
            UserSession.limpiar()
            startActivity(Intent(this, MainActivity::class.java))
            finish()
        }

        // ── Registro ──────────────────────────────────────────────────────
        binding.btnRegistrar.setOnClickListener {
            val nombre    = binding.etNombreReg.text.toString().trim()
            val apellido  = binding.etApellidoReg.text.toString().trim()
            val usuario   = binding.etUsuarioReg.text.toString().trim()
            val correo    = binding.etCorreoReg.text.toString().trim()
            val password  = binding.etPasswordReg.text.toString().trim()
            val confirmar = binding.etConfirmReg.text.toString().trim()

            if (nombre.isEmpty() || apellido.isEmpty() || usuario.isEmpty() ||
                correo.isEmpty() || password.isEmpty() || confirmar.isEmpty()) {
                Toast.makeText(this, "Completa todos los campos", Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }
            if (password != confirmar) {
                Toast.makeText(this, "Las contraseñas no coinciden", Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }
            registrar(nombre, apellido, usuario, correo, password)
        }
    }

    // ── Helpers de tab ───────────────────────────────────────────────────
    private fun mostrarLogin() {
        binding.layoutLogin.visibility    = View.VISIBLE
        binding.layoutRegistro.visibility = View.GONE
        binding.tvTabLogin.setTextColor(getColor(R.color.green_primary))
        binding.tvTabLogin.setTypeface(null, android.graphics.Typeface.BOLD)
        binding.viewLineaLogin.visibility = View.VISIBLE
        binding.tvTabRegistro.setTextColor(getColor(R.color.text_secondary))
        binding.tvTabRegistro.setTypeface(null, android.graphics.Typeface.NORMAL)
        binding.viewLineaRegistro.visibility = View.INVISIBLE
    }

    private fun mostrarRegistro() {
        binding.layoutLogin.visibility    = View.GONE
        binding.layoutRegistro.visibility = View.VISIBLE
        binding.tvTabRegistro.setTextColor(getColor(R.color.green_primary))
        binding.tvTabRegistro.setTypeface(null, android.graphics.Typeface.BOLD)
        binding.viewLineaRegistro.visibility = View.VISIBLE
        binding.tvTabLogin.setTextColor(getColor(R.color.text_secondary))
        binding.tvTabLogin.setTypeface(null, android.graphics.Typeface.NORMAL)
        binding.viewLineaLogin.visibility = View.INVISIBLE
    }

    // ── Login: validar y redirigir según rol ─────────────────────────────
    private fun iniciarSesion(usuario: String, contrasena: String) {
        val queue = Volley.newRequestQueue(this)
        val request = object : StringRequest(
            Method.POST, ApiConfig.LOGIN,
            { response ->
                try {
                    val json = JSONObject(response)
                    if (json.getBoolean("ok")) {
                        val u = json.getJSONObject("usuario")
                        UserSession.usuario  = u.optString("usuario",  "")
                        UserSession.nombre   = u.optString("nombre",   "")
                        UserSession.apellido = u.optString("apellido", "")
                        UserSession.rol      = u.optString("rol",      "2")

                        // ── Redirigir según rol ──────────────────────────
                        val destino: Class<*> = when {
                            UserSession.isAdmin    -> AdminMainActivity::class.java
                            UserSession.isEmpleado -> EmpleadoMainActivity::class.java
                            else                   -> MainActivity::class.java
                        }
                        startActivity(Intent(this, destino))
                        finish()
                    } else {
                        Toast.makeText(this, json.getString("mensaje"), Toast.LENGTH_SHORT).show()
                    }
                } catch (_: Exception) {
                    Toast.makeText(this, "Error procesando respuesta", Toast.LENGTH_SHORT).show()
                }
            },
            { error -> Toast.makeText(this, error.message ?: "Error de red", Toast.LENGTH_SHORT).show() }
        ) {
            override fun getParams() = mapOf("usuario" to usuario, "contrasena" to contrasena)
        }
        queue.add(request)
    }

    // ── Registro: enviar correo para que el servidor asigne el rol ───────
    private fun registrar(nombre: String, apellido: String, usuario: String,
                          correo: String, contrasena: String) {
        val queue = Volley.newRequestQueue(this)
        val request = object : StringRequest(
            Method.POST, ApiConfig.REGISTER,
            { response ->
                try {
                    val json = JSONObject(response)
                    if (json.getBoolean("ok")) {
                        Toast.makeText(this, json.optString("mensaje",
                            "¡Cuenta creada! Ahora inicia sesión"), Toast.LENGTH_LONG).show()
                        binding.etNombreReg.text?.clear()
                        binding.etApellidoReg.text?.clear()
                        binding.etUsuarioReg.text?.clear()
                        binding.etCorreoReg.text?.clear()
                        binding.etPasswordReg.text?.clear()
                        binding.etConfirmReg.text?.clear()
                        mostrarLogin()
                    } else {
                        Toast.makeText(this, json.getString("mensaje"), Toast.LENGTH_SHORT).show()
                    }
                } catch (_: Exception) {
                    Toast.makeText(this, "Error procesando respuesta", Toast.LENGTH_SHORT).show()
                }
            },
            { error -> Toast.makeText(this, error.message ?: "Error de red", Toast.LENGTH_SHORT).show() }
        ) {
            override fun getParams() = mapOf(
                "nombre"     to nombre,
                "apellido"   to apellido,
                "usuario"    to usuario,
                "correo"     to correo,
                "contrasena" to contrasena
            )
        }
        queue.add(request)
    }
}

package com.david.tiendavirtual.ui.productos

import android.content.Intent
import android.content.res.ColorStateList
import android.os.Bundle
import android.view.View
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.ContextCompat
import com.bumptech.glide.Glide
import com.david.tiendavirtual.R
import com.david.tiendavirtual.data.model.Producto
import com.david.tiendavirtual.databinding.ActivityProductoDetalleBinding
import com.google.android.material.chip.Chip
import com.david.tiendavirtual.ui.carrito.CarritoActivity

class ProductoDetalleActivity : AppCompatActivity() {

    private lateinit var binding: ActivityProductoDetalleBinding
    private lateinit var producto: Producto
    private var cantidadSeleccionada = 1

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        binding = ActivityProductoDetalleBinding.inflate(layoutInflater)
        setContentView(binding.root)

        @Suppress("DEPRECATION")
        producto = intent.getSerializableExtra("producto") as Producto

        setupUI()
    }

    private fun setupUI() {

        // ── Botón volver ─────────────────────────────────────────────────
        binding.btnVolverDetalle.setOnClickListener { finish() }

        // ── Imagen del producto con Glide ─────────────────────────────────
        val imgUrl = producto.imagen
        if (!imgUrl.isNullOrEmpty()) {
            binding.ivDetalleImagen.clearColorFilter()
            binding.ivDetalleImagen.alpha = 1f
            Glide.with(this)
                .load(imgUrl)
                .placeholder(R.drawable.ic_cart)
                .error(R.drawable.ic_cart)
                .centerCrop()
                .into(binding.ivDetalleImagen)
        } else {
            binding.ivDetalleImagen.setImageResource(R.drawable.ic_cart)
            binding.ivDetalleImagen.setColorFilter(
                ContextCompat.getColor(this, R.color.green_primary)
            )
            binding.ivDetalleImagen.alpha = 0.35f
        }

        // ── Nombre ───────────────────────────────────────────────────────
        binding.tvDetalleNombre.text = producto.nombre

        // ── Categoría · Marca ────────────────────────────────────────────
        val catMarca = listOfNotNull(
            producto.categoria?.takeIf { it.isNotEmpty() },
            producto.marca?.takeIf { it.isNotEmpty() }
        ).joinToString(" · ")
        binding.tvDetalleCategoria.text = catMarca

        // ── Rating (valor determinístico por idProducto) ──────────────────
        val rating       = 3.8 + (producto.idProducto % 12) * 0.1
        val reviews      = 50  + (producto.idProducto % 200).toInt()
        val satisfaccion = 82  + (producto.idProducto % 17).toInt()

        binding.ratingBarDetalle.rating     = rating.toFloat()
        binding.tvDetalleRating.text        = "%.1f".format(rating)
        binding.tvDetalleSatisfaccion.text  = "$satisfaccion%"
        binding.tvDetalleReviews.text       = "$reviews reseñas"

        // ── Descripción ──────────────────────────────────────────────────
        binding.tvDetalleDescripcion.text = producto.descripcion

        // ── Precio ───────────────────────────────────────────────────────
        val precioOriginal = producto.precioVenta * 1.18
        binding.tvDetallePrecio.text         = "B/. %.2f".format(producto.precioVenta)
        binding.tvDetallePrecioAnterior.text = "B/. %.2f".format(precioOriginal)
        // Strikethrough para el precio anterior
        binding.tvDetallePrecioAnterior.paintFlags =
            binding.tvDetallePrecioAnterior.paintFlags or android.graphics.Paint.STRIKE_THRU_TEXT_FLAG

        // ── Stock ────────────────────────────────────────────────────────
        if (producto.stock > 0) {
            binding.tvDetalleStock.text = "${producto.stock} en stock"
        } else {
            binding.tvDetalleStock.text = "Agotado"
            binding.tvDetalleStock.setTextColor(ContextCompat.getColor(this, android.R.color.holo_red_dark))
        }

        // ── Badge oferta ─────────────────────────────────────────────────
        val descuento = ((precioOriginal - producto.precioVenta) / precioOriginal * 100).toInt()
        binding.tvBadgeSale.text = "-$descuento%"

        // ── Variantes ────────────────────────────────────────────────────
        val variantes = extraerVariantes(producto.nombre)
        if (variantes.isNotEmpty()) {
            val colorVerde  = ContextCompat.getColor(this, R.color.green_primary)
            val colorBlanco = ContextCompat.getColor(this, R.color.white)
            val colorTexto  = ContextCompat.getColor(this, R.color.text_primary)

            val bgStates = arrayOf(intArrayOf(android.R.attr.state_checked), intArrayOf())
            val bgColors = intArrayOf(colorVerde, colorBlanco)
            val bgList   = ColorStateList(bgStates, bgColors)

            val txtStates = arrayOf(intArrayOf(android.R.attr.state_checked), intArrayOf())
            val txtColors = intArrayOf(colorBlanco, colorTexto)
            val txtList   = ColorStateList(txtStates, txtColors)

            variantes.forEachIndexed { index, spec ->
                val chip = Chip(this).apply {
                    text                = spec
                    isCheckable         = true
                    isChecked           = (index == 0)
                    chipBackgroundColor = bgList
                    setTextColor(txtList)
                    chipStrokeWidth     = 1.5f
                    setChipStrokeColorResource(R.color.green_primary)
                }
                binding.chipGroupVariantes.addView(chip)
            }
            binding.variantesSection.visibility = View.VISIBLE
        } else {
            binding.variantesSection.visibility = View.GONE
        }

        // ── Favorito ─────────────────────────────────────────────────────
        actualizarFavorito()
        binding.btnFavoritoDetalle.setOnClickListener {
            FavoritosManager.alternar(producto)
            actualizarFavorito()
        }

        // ── Compartir ────────────────────────────────────────────────────
        binding.btnCompartirDetalle.setOnClickListener {
            val sendIntent = Intent(Intent.ACTION_SEND).apply {
                type = "text/plain"
                putExtra(Intent.EXTRA_TEXT,
                    "¡Mira este producto! ${producto.nombre} — B/. %.2f".format(producto.precioVenta))
            }
            startActivity(Intent.createChooser(sendIntent, "Compartir producto"))
        }

        // ── Selector de cantidad ─────────────────────────────────────────
        actualizarSelectorCantidad()
        binding.btnRestarCantidad.setOnClickListener {
            if (cantidadSeleccionada > 1) {
                cantidadSeleccionada--
                actualizarSelectorCantidad()
            }
        }
        binding.btnSumarCantidad.setOnClickListener {
            if (cantidadSeleccionada < producto.stock) {
                cantidadSeleccionada++
                actualizarSelectorCantidad()
            } else {
                Snackbar.make(binding.root, "No hay más stock disponible", Snackbar.LENGTH_SHORT).show()
            }
        }

        // ── Agregar al carrito ────────────────────────────────────────────
        binding.btnAgregarCarritoDetalle.setOnClickListener {
            if (producto.stock <= 0) {
                android.widget.Toast.makeText(this, "Producto sin stock disponible", android.widget.Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }
            CarritoManager.agregarProducto(producto, cantidadSeleccionada)

            // Micro-animación feedback y luego ir al carrito
            binding.btnAgregarCarritoDetalle.animate()
                .scaleX(0.95f).scaleY(0.95f).setDuration(80)
                .withEndAction {
                    binding.btnAgregarCarritoDetalle.animate()
                        .scaleX(1f).scaleY(1f).setDuration(120)
                        .withEndAction {
                            startActivity(Intent(this, CarritoActivity::class.java))
                        }.start()
                }.start()
        }
    }

    // ── Helpers ──────────────────────────────────────────────────────────

    private fun actualizarFavorito() {
        val esFav = FavoritosManager.esFavorito(producto.idProducto)
        binding.ivFavoritoDetalle.setColorFilter(
            ContextCompat.getColor(
                this,
                if (esFav) R.color.green_primary else R.color.text_secondary
            )
        )
    }

    /** Actualiza el texto del selector de cantidad y el estado del botón - */
    private fun actualizarSelectorCantidad() {
        binding.tvCantidadDetalle.text = cantidadSeleccionada.toString()
        binding.btnRestarCantidad.alpha = if (cantidadSeleccionada <= 1) 0.4f else 1f
        binding.btnSumarCantidad.alpha  = if (cantidadSeleccionada >= producto.stock) 0.4f else 1f
    }

    /** Extrae specs clave del nombre del producto (GB, TB, W, MHz, DDR4/5). */
    private fun extraerVariantes(nombre: String): List<String> {
        val patterns = listOf(
            Regex("\\d+(?:\\.\\d+)?\\s?TB"),
            Regex("\\d+(?:\\.\\d+)?\\s?GB"),
            Regex("\\d+\\s?W(?=\\b)"),
            Regex("DDR[45]"),
            Regex("\\d+\\s?MHz"),
        )
        return patterns.mapNotNull { it.find(nombre)?.value?.trim() }
    }
}

package com.david.tiendavirtual.ui.productos

import android.content.Intent
import android.content.res.ColorStateList
import android.os.Bundle
import android.view.View
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.ContextCompat
import com.bumptech.glide.Glide
import com.david.tiendavirtual.R
import com.david.tiendavirtual.data.model.Producto
import com.david.tiendavirtual.databinding.ActivityProductoDetalleBinding
import com.google.android.material.chip.Chip
import com.david.tiendavirtual.ui.carrito.CarritoActivity
import com.google.android.material.snackbar.Snackbar

