        binding.tvDetallePrecio.text         = "B/. %.2f".format(producto.precioVenta)
        binding.tvDetallePrecioAnterior.text = "B/. %.2f".format(precioOriginal)
        // Strikethrough para el precio anterior
        binding.tvDetallePrecioAnterior.paintFlags =
            binding.tvDetallePrecioAnterior.paintFlags or android.graphics.Paint.STRIKE_THRU_TEXT_FLAG

        // ── Stock ────────────────────────────────────────────────────────
        if (producto.stock > 0) {
